import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './components/Layout';
import Home from './pages/Home';
import Profile from './pages/Profile';
import Services from './pages/Services';
import Chat from './pages/Chat';
import SupportAI from './pages/SupportAI';
import AddProject from './pages/AddProject';
import UsagePolicy from './pages/UsagePolicy';
import PrivacyPolicy from './pages/PrivacyPolicy';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(true); // Mock Auth

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
    if (!isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<Layout toggleTheme={toggleTheme} isDarkMode={isDarkMode} />}>
          <Route index element={<Home />} />
          <Route path="profile" element={isAuthenticated ? <Profile /> : <Navigate to="/" />} />
          <Route path="services" element={<Services />} />
          <Route path="chat" element={<Chat />} />
          <Route path="support" element={<SupportAI />} />
          <Route path="add-project" element={<AddProject />} />
          <Route path="usage-policy" element={<UsagePolicy />} />
          <Route path="privacy-policy" element={<PrivacyPolicy />} />
        </Route>
      </Routes>
    </HashRouter>
  );
};

export default App;

export enum UserRole {
  USER = 'USER',
  DEVELOPER = 'DEVELOPER'
}

export interface User {
  id: string;
  username: string;
  fullName: string;
  email: string;
  avatar: string;
  role: UserRole;
  points: number;
  gender?: 'Male' | 'Female';
  dob?: string;
  location?: string;
  isVerified?: boolean;
}

export interface AppProject {
  id: string;
  name: string;
  description: string;
  developer: string;
  icon: string;
  screenshots: string[];
  downloads: number;
  views: number;
  likes: number;
  type: 'Game' | 'App' | 'Site' | 'Store';
  region: string;
  isPaid: boolean;
  apkUrl?: string;
  ipaUrl?: string;
}

export type PlanDuration = 'daily' | 'monthly' | 'yearly';

export interface SubscriptionPlan {
  id: string;
  title: string;
  description: string;
  prices: {
    daily: number;
    monthly: number;
    yearly: number;
  };
  features: string[];
  isPopular?: boolean;
  isNewUser?: boolean; // For the short-term new user plan
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: number;
  type: 'text' | 'audio' | 'location' | 'image';
}

import React, { useState } from 'react';
import { NavLink, Outlet, useLocation } from 'react-router-dom';
import { Home, User, MessageSquare, Zap, Search, Bell, Sun, Moon, PlusCircle, HelpCircle, Share } from 'lucide-react';
import { APP_SHARE_URL } from '../constants';

interface LayoutProps {
  toggleTheme: () => void;
  isDarkMode: boolean;
}

export const Layout: React.FC<LayoutProps> = ({ toggleTheme, isDarkMode }) => {
  const location = useLocation();
  const [showSearch, setShowSearch] = useState(false);

  const isActive = (path: string) => location.pathname === path;

  const handleShare = async () => {
    const shareData = {
      title: 'Ideas App',
      text: 'تواصل مع أفضل المطورين وابنِ مشروعك الآن عبر تطبيق Ideas',
      url: APP_SHARE_URL,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing:', err);
      }
    } else {
      // Fallback
      navigator.clipboard.writeText(APP_SHARE_URL);
      alert('تم نسخ رابط التطبيق!');
    }
  };

  return (
    <div className={`min-h-screen flex flex-col ${isDarkMode ? 'bg-gray-900 text-white' : 'bg-white text-black'}`}>

      {/* Top Navbar */}
      <header className={`sticky top-0 z-50 border-b ${isDarkMode ? 'border-gray-800 bg-gray-900' : 'border-gray-200 bg-white'} transition-colors duration-200`}>
        <div className="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <button onClick={toggleTheme} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition">
                {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
             </button>
             <button onClick={handleShare} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition text-blue-600">
                <Share size={20} />
             </button>
          </div>

          <div className="font-bold text-xl tracking-tighter">IDEAS</div>

          <div className="flex items-center gap-2">
             <div className="relative">
                <Bell size={20} />
                <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full"></span>
             </div>
             <button onClick={() => setShowSearch(!showSearch)} className="p-2">
               <Search size={22} />
             </button>
          </div>
        </div>

        {/* Expanded Search Bar */}
        {showSearch && (
          <div className="px-4 pb-4 max-w-4xl mx-auto animate-in slide-in-from-top-2">
            <input 
              type="text" 
              placeholder="بحث عن مشاريع (تطبيقات، ألعاب...)" 
              className={`w-full p-3 rounded-xl border ${isDarkMode ? 'bg-gray-800 border-gray-700' : 'bg-gray-50 border-black'} focus:outline-none focus:ring-1 focus:ring-black`}
            />
          </div>
        )}
      </header>

      {/* Main Content Area */}
      <main className="flex-1 max-w-4xl mx-auto w-full p-4 mb-20 overflow-y-auto">
        <Outlet />
      </main>

      {/* Bottom Navigation (Mobile First Sticky) */}
      <nav className={`fixed bottom-0 w-full border-t ${isDarkMode ? 'border-gray-800 bg-gray-900' : 'border-gray-200 bg-white'} pb-safe z-40`}>
        <div className="max-w-4xl mx-auto flex justify-around items-center h-16">
          <NavLink to="/" className={`flex flex-col items-center gap-1 p-2 ${isActive('/') ? 'text-black font-bold scale-110' : 'text-gray-400'}`}>
            <Home size={24} strokeWidth={isActive('/') ? 3 : 2} />
            <span className="text-[10px]">الرئيسية</span>
          </NavLink>

          <NavLink to="/services" className={`flex flex-col items-center gap-1 p-2 ${isActive('/services') ? 'text-black font-bold scale-110' : 'text-gray-400'}`}>
            <Zap size={24} strokeWidth={isActive('/services') ? 3 : 2} />
            <span className="text-[10px]">الباقات</span>
          </NavLink>

           <NavLink to="/add-project" className={`flex flex-col items-center justify-center -mt-6`}>
            <div className="bg-black text-white p-4 rounded-full shadow-lg hover:scale-105 transition">
               <PlusCircle size={28} />
            </div>
          </NavLink>

          <NavLink to="/chat" className={`flex flex-col items-center gap-1 p-2 ${isActive('/chat') ? 'text-black font-bold scale-110' : 'text-gray-400'}`}>
            <MessageSquare size={24} strokeWidth={isActive('/chat') ? 3 : 2} />
            <span className="text-[10px]">الدردشة</span>
          </NavLink>

          <NavLink to="/profile" className={`flex flex-col items-center gap-1 p-2 ${isActive('/profile') ? 'text-black font-bold scale-110' : 'text-gray-400'}`}>
            <User size={24} strokeWidth={isActive('/profile') ? 3 : 2} />
            <span className="text-[10px]">حسابي</span>
          </NavLink>
        </div>
      </nav>

      {/* Floating Support Button */}
      <NavLink to="/support" className="fixed bottom-20 left-4 z-40 bg-black text-white p-3 rounded-full shadow-xl hover:bg-gray-800 transition">
        <HelpCircle size={24} />
      </NavLink>

    </div>
  );
};

import React, { useState } from 'react';
import { User, Mail, Lock, ArrowRight } from 'lucide-react';

interface RegisterProps {
    onRegister: () => void;
}

const Register: React.FC<RegisterProps> = ({ onRegister }) => {
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        // In a real app, validation and API call would go here
        if (name && email && password) {
            onRegister();
        }
    };

    return (
        <div className="min-h-screen bg-white p-6 flex flex-col justify-center animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="max-w-md mx-auto w-full">
                <div className="mb-10 text-center">
                    <h1 className="text-4xl font-extrabold mb-2 tracking-tighter">IDEAS</h1>
                    <p className="text-gray-500">أنشئ حسابك الجديد وابدأ رحلتك</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="space-y-2">
                        <label className="text-sm font-bold flex items-center gap-2">
                            <User size={16} /> الاسم الكامل
                        </label>
                        <input 
                            type="text" 
                            required
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="w-full p-4 bg-gray-50 rounded-xl border-none focus:ring-2 focus:ring-black transition"
                            placeholder="محمد علي"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-bold flex items-center gap-2">
                            <Mail size={16} /> البريد الإلكتروني
                        </label>
                        <input 
                            type="email" 
                            required
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="w-full p-4 bg-gray-50 rounded-xl border-none focus:ring-2 focus:ring-black transition"
                            placeholder="example@mail.com"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-bold flex items-center gap-2">
                            <Lock size={16} /> كلمة المرور
                        </label>
                        <input 
                            type="password" 
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="w-full p-4 bg-gray-50 rounded-xl border-none focus:ring-2 focus:ring-black transition"
                            placeholder="********"
                        />
                    </div>

                    <button 
                        type="submit"
                        className="w-full bg-black text-white py-4 rounded-xl font-bold text-lg hover:bg-gray-800 transition flex items-center justify-center gap-2 mt-8"
                    >
                        إنشاء حساب <ArrowRight size={20} />
                    </button>
                </form>

                <p className="text-center text-xs text-gray-400 mt-8 leading-relaxed">
                    بإنشاء حساب، أنت توافق على <br/>
                    <span className="underline">سياسة الاستخدام</span> و <span className="underline">سياسة الخصوصية</span>
                </p>
            </div>
        </div>
    );
};

export default Register;

import React, { useState } from 'react';
import { SUBSCRIPTION_PLANS, WALLETS } from '../constants';
import { PlanDuration, SubscriptionPlan } from '../types';
import { Check, Copy, CreditCard, Wallet, ShieldCheck, X } from 'lucide-react';

const Services: React.FC = () => {
  const [selectedDuration, setSelectedDuration] = useState<PlanDuration>('monthly');
  const [selectedPlan, setSelectedPlan] = useState<SubscriptionPlan | null>(null);
  const [paymentStep, setPaymentStep] = useState(0); // 0: Closed, 1: Details, 2: Wallet, 3: User Wallet, 4: Hash, 5: Success

  // Payment Form State
  const [selectedWallet, setSelectedWallet] = useState('');
  const [userWalletAddress, setUserWalletAddress] = useState('');
  const [transactionHash, setTransactionHash] = useState('');
  const [copySuccess, setCopySuccess] = useState('');

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopySuccess('تم النسخ!');
    setTimeout(() => setCopySuccess(''), 2000);
  };

  const openPaymentModal = (plan: SubscriptionPlan) => {
    setSelectedPlan(plan);
    setPaymentStep(1);
    // Reset form
    setSelectedWallet('');
    setUserWalletAddress('');
    setTransactionHash('');
  };

  const nextStep = () => {
    if (paymentStep === 2 && !selectedWallet) return alert('يرجى اختيار محفظة');
    if (paymentStep === 3 && !userWalletAddress) return alert('يرجى إدخال عنوان محفظتك');
    if (paymentStep === 4 && !transactionHash) return alert('يرجى إدخال رمز التحقق');
    setPaymentStep(prev => prev + 1);
  };

  const renderPaymentModal = () => {
    if (!selectedPlan || paymentStep === 0) return null;

    return (
      <div className="fixed inset-0 bg-black/80 z-[60] flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-300">
        <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl">

          {/* Header */}
          <div className="bg-gray-50 p-4 border-b flex justify-between items-center">
            <h3 className="font-bold text-lg">
              {paymentStep === 5 ? 'تمت العملية' : `خطوة ${paymentStep} من 4`}
            </h3>
            <button onClick={() => setPaymentStep(0)} className="p-1 hover:bg-gray-200 rounded-full">
              <X size={20} />
            </button>
          </div>

          {/* Content */}
          <div className="p-6">

            {/* Step 1: Confirmation */}
            {paymentStep === 1 && (
              <div className="space-y-4 text-center">
                <div className="w-16 h-16 bg-black text-white rounded-full flex items-center justify-center mx-auto mb-4">
                  <CreditCard size={32} />
                </div>
                <h4 className="text-xl font-bold">تأكيد الاشتراك</h4>
                <div className="bg-gray-50 p-4 rounded-xl border">
                  <p className="font-bold text-lg">{selectedPlan.title}</p>
                  <p className="text-gray-500 text-sm">مدة الاشتراك: {
                    selectedDuration === 'daily' ? 'يومي' : selectedDuration === 'monthly' ? 'شهري' : 'سنوي'
                  }</p>
                  <p className="text-2xl font-extrabold mt-2">{selectedPlan.prices[selectedDuration]} ﷼</p>
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold hover:scale-[1.02] transition">
                  تأكيد والمتابعة
                </button>
              </div>
            )}

            {/* Step 2: Select Wallet */}
            {paymentStep === 2 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg mb-2">اختر طريقة الدفع</h4>
                <p className="text-xs text-gray-500 mb-4">اختر المحفظة التي ستقوم بالتحويل إليها:</p>
                <div className="max-h-60 overflow-y-auto space-y-2 pr-1">
                  {WALLETS.map(w => (
                    <div 
                      key={w.name}
                      onClick={() => setSelectedWallet(w.name)}
                      className={`p-3 rounded-xl border cursor-pointer flex justify-between items-center transition ${selectedWallet === w.name ? 'border-black bg-black text-white' : 'border-gray-200 hover:bg-gray-50'}`}
                    >
                      <span className="font-bold">{w.name}</span>
                      <span className="text-xs opacity-70">{w.symbol}</span>
                    </div>
                  ))}
                </div>
                {selectedWallet && (
                   <div className="bg-gray-100 p-3 rounded-lg mt-4 text-xs break-all relative">
                     <p className="font-mono text-gray-600 mb-1">عنوان المحفظة:</p>
                     {WALLETS.find(w => w.name === selectedWallet)?.address}
                     <button 
                        onClick={() => handleCopy(WALLETS.find(w => w.name === selectedWallet)?.address || '')}
                        className="absolute top-2 left-2 bg-black text-white p-1 rounded"
                     >
                       <Copy size={12} />
                     </button>
                     {copySuccess && <span className="absolute bottom-1 left-2 text-green-600 font-bold">{copySuccess}</span>}
                   </div>
                )}
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  التالي
                </button>
              </div>
            )}

            {/* Step 3: User Wallet */}
            {paymentStep === 3 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg">عنوان محفظتك</h4>
                <p className="text-sm text-gray-500">يرجى لصق عنوان المحفظة التي قمت بالتحويل منها لنتحقق من المصدر.</p>
                <div className="relative">
                    <Wallet className="absolute top-3 right-3 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      value={userWalletAddress}
                      onChange={(e) => setUserWalletAddress(e.target.value)}
                      placeholder="لصق عنوان محفظتك هنا..."
                      className="w-full p-3 pr-10 bg-gray-50 rounded-xl border focus:border-black outline-none font-mono text-sm"
                    />
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  التالي
                </button>
              </div>
            )}

            {/* Step 4: Transaction Hash */}
            {paymentStep === 4 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg">إثبات الدفع</h4>
                <p className="text-sm text-gray-500">يرجى لصق رمز التحقق من المعاملة (Hash / Transaction ID).</p>
                <div className="relative">
                    <ShieldCheck className="absolute top-3 right-3 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      value={transactionHash}
                      onChange={(e) => setTransactionHash(e.target.value)}
                      placeholder="Transaction Hash / ID..."
                      className="w-full p-3 pr-10 bg-gray-50 rounded-xl border focus:border-black outline-none font-mono text-sm"
                    />
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  إتمام الاشتراك
                </button>
              </div>
            )}

            {/* Step 5: Success */}
            {paymentStep === 5 && (
              <div className="text-center py-8 space-y-4 animate-in zoom-in duration-300">
                <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto">
                  <Check size={40} strokeWidth={3} />
                </div>
                <h4 className="text-2xl font-bold">تم الاشتراك بنجاح!</h4>
                <p className="text-gray-500">جاري مراجعة عملية الدفع وتفعيل الباقة.<br/>شكراً لاختيارك Ideas.</p>
                <button onClick={() => setPaymentStep(0)} className="w-full bg-gray-100 text-black py-3 rounded-xl font-bold mt-4 hover:bg-gray-200">
                  إغلاق
                </button>
              </div>
            )}

          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">

      {/* Header */}
      <div className="text-center space-y-4">
        <h1 className="text-3xl font-extrabold tracking-tight">اختر خطة الاشتراك</h1>
        <p className="text-gray-500 text-sm max-w-md mx-auto">أسعار متزنة تناسب الجميع، ابدأ رحلتك الآن.</p>

        {/* Duration Tabs */}
        <div className="flex justify-center p-1 bg-gray-100 rounded-full w-max mx-auto">
          {(['daily', 'monthly', 'yearly'] as PlanDuration[]).map((d) => (
            <button
              key={d}
              onClick={() => setSelectedDuration(d)}
              className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${
                selectedDuration === d 
                ? 'bg-black text-white shadow-md' 
                : 'text-gray-500 hover:text-black'
              }`}
            >
              {d === 'daily' ? 'يومي' : d === 'monthly' ? 'شهري' : 'سنوي'}
            </button>
          ))}
        </div>
      </div>

      {/* Pricing Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {SUBSCRIPTION_PLANS.map((plan) => (
          <div 
            key={plan.id} 
            className={`relative flex flex-col p-6 rounded-3xl border transition-all duration-300 ${
              plan.isPopular 
                ? 'bg-black text-white border-black shadow-xl scale-[1.02]' 
                : 'bg-white text-black border-gray-100 hover:border-gray-300 shadow-sm'
            }`}
          >
            {plan.isPopular && (
              <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-yellow-400 text-black text-[10px] font-extrabold px-3 py-1 rounded-full">
                الأكثر طلباً
              </span>
            )}
             {plan.isNewUser && (
              <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-green-500 text-white text-[10px] font-extrabold px-3 py-1 rounded-full">
                للمستخدم الجديد
              </span>
            )}

            <div className="mb-4">
              <h3 className="text-lg font-bold">{plan.title}</h3>
              <p className={`text-xs ${plan.isPopular ? 'text-gray-400' : 'text-gray-500'}`}>{plan.description}</p>
            </div>

            <div className="mb-6">
              <span className="text-3xl font-extrabold">{plan.prices[selectedDuration]}</span>
              <span className="text-sm mx-1">﷼</span>
              <span className={`text-xs ${plan.isPopular ? 'text-gray-500' : 'text-gray-400'}`}>
                 / {selectedDuration === 'daily' ? 'يوم' : selectedDuration === 'monthly' ? 'شهر' : 'سنة'}
              </span>
            </div>

            <ul className="space-y-3 mb-8 flex-1">
              {plan.features.map((feature, i) => (
                <li key={i} className="flex items-center gap-2 text-sm">
                  <div className={`p-0.5 rounded-full ${plan.isPopular ? 'bg-white/20' : 'bg-black/5'}`}>
                    <Check size={12} className={plan.isPopular ? 'text-white' : 'text-black'} />
                  </div>
                  <span className={plan.isPopular ? 'text-gray-300' : 'text-gray-600'}>{feature}</span>
                </li>
              ))}
            </ul>

            <button 
              onClick={() => openPaymentModal(plan)}
              className={`w-full py-3 rounded-xl font-bold transition ${
                plan.isPopular 
                  ? 'bg-white text-black hover:bg-gray-200' 
                  : 'bg-black text-white hover:bg-gray-800'
              }`}
            >
              اشترك الآن
            </button>
          </div>
        ))}
      </div>

      {renderPaymentModal()}

    </div>
  );
};

export default Services;

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './components/Layout';
import Home from './pages/Home';
import Profile from './pages/Profile';
import Services from './pages/Services';
import Chat from './pages/Chat';
import SupportAI from './pages/SupportAI';
import AddProject from './pages/AddProject';
import UsagePolicy from './pages/UsagePolicy';
import PrivacyPolicy from './pages/PrivacyPolicy';
import Register from './pages/Register';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false); 

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
    if (!isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  const handleRegister = () => {
    setIsAuthenticated(true);
  };

  return (
    <HashRouter>
      <Routes>
        <Route path="/register" element={
            !isAuthenticated ? <Register onRegister={handleRegister} /> : <Navigate to="/" />
        } />

        <Route path="/" element={isAuthenticated ? <Layout toggleTheme={toggleTheme} isDarkMode={isDarkMode} /> : <Navigate to="/register" />}>
