import React, { useState, useEffect, useRef } from 'react';
import { Send, Mic, MapPin, Image as ImageIcon } from 'lucide-react';
import { ChatMessage } from '../types';

const Chat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;

    const newMessage: ChatMessage = {
      id: Date.now().toString(),
      senderId: 'user',
      text: inputText,
      timestamp: Date.now(),
      type: 'text'
    };

    setMessages(prev => [...prev, newMessage]);
    setInputText('');

    // Simulate Developer Reply (Simplified)
    setTimeout(() => {
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        senderId: 'dev',
        text: 'شكراً لتواصلك. سأقوم بالرد عليك قريباً.',
        timestamp: Date.now(),
        type: 'text'
      }]);
    }, 1500);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">

      {/* Chat Header */}
      <div className="p-4 bg-gray-50 border-b flex items-center gap-3">
        <div className="relative">
            <img src="https://ui-avatars.com/api/?name=Jacob+Al+Cadi&background=000&color=fff" className="w-10 h-10 rounded-full" alt="Dev" />
            <span className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 rounded-full border-2 border-white"></span>
        </div>
        <div>
            <h3 className="font-bold text-sm">Jacob Al Cadi</h3>
            <span className="text-xs text-gray-500">مطور تطبيقات</span>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-gray-400 text-sm">
                <p>لا توجد رسائل سابقة</p>
                <p className="text-xs mt-1">ابدأ المحادثة الآن</p>
            </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.senderId === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[75%] p-3 rounded-2xl text-sm ${
              msg.senderId === 'user' 
                ? 'bg-black text-white rounded-br-none' 
                : 'bg-gray-100 text-black rounded-bl-none'
            }`}>
              {msg.text}
              <span className="block text-[10px] opacity-50 mt-1 text-right">
                {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
              </span>
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-3 border-t bg-white">
        <div className="flex items-center gap-2 bg-gray-50 p-2 rounded-full">
            <button className="p-2 text-gray-400 hover:text-black"><Mic size={20} /></button>
            <button className="p-2 text-gray-400 hover:text-black"><ImageIcon size={20} /></button>
            <button className="p-2 text-gray-400 hover:text-black"><MapPin size={20} /></button>
            <input 
                type="text" 
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="اكتب رسالتك..." 
                className="flex-1 bg-transparent focus:outline-none px-2 text-sm"
            />
            <button onClick={handleSend} className="p-2 bg-black text-white rounded-full hover:scale-105 transition">
                <Send size={18} className="ml-0.5" />
            </button>
        </div>
      </div>

    </div>
  );
};

