      const result = await generateSupportResponse(query);
      setResponse(result);
    } catch (e) {
      setResponse("حدث خطأ غير متوقع.");
    } finally {
      setLoading(false);
    }
  };

  const openGmailCompose = () => {
      // Direct link to Gmail web compose
      const subject = encodeURIComponent("استفسار من تطبيق ideas");
      const url = `https://mail.google.com/mail/?view=cm&fs=1&to=jikob67@gmail.com&su=${subject}`;
      window.open(url, '_blank');
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">

      <div className="bg-black text-white p-8 rounded-3xl text-center relative overflow-hidden">
        <Bot size={64} className="mx-auto mb-4 text-gray-400" />
