          <button 
            onClick={handleAskAI} 
            disabled={loading}
            className="flex items-center gap-2 bg-black text-white px-6 py-2 rounded-full font-bold disabled:opacity-50 hover:bg-gray-800 transition"
          >
            {loading ? 'جاري التفكير...' : 'إرسال'}
            {!loading && <Send size={16} />}
