      </div>

      {/* AI Response */}
      {response && (
        <div className="bg-gray-50 p-6 rounded-3xl border border-gray-200 animate-in slide-in-from-bottom-2">
           <div className="flex items-center gap-2 mb-2 font-bold text-sm text-gray-500">
             <Bot size={16} /> المساعد الذكي
           </div>
           <p className="whitespace-pre-wrap leading-relaxed">{response}</p>
        </div>
      )}

      {/* Gmail Integration & Fallback */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 px-2">
             <h3 className="font-bold text-lg">تواصل معنا</h3>
             <div className="h-px flex-1 bg-gray-100"></div>
        </div>

        {/* Primary Gmail Button */}
        <button 
            onClick={openGmailCompose}
            className="w-full bg-white border border-gray-200 p-4 rounded-2xl hover:border-red-200 hover:bg-red-50 transition group flex items-center justify-between"
        >
            <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600 group-hover:scale-110 transition">
                    <Mail size={24} />
