import React, { useState } from 'react';
import { SUBSCRIPTION_PLANS, WALLETS } from '../constants';
import { PlanDuration, SubscriptionPlan, AppContextType } from '../types';
import { Check, Copy, CreditCard, Wallet, ShieldCheck, X } from 'lucide-react';
import { useOutletContext, useNavigate } from 'react-router-dom';

const Services: React.FC = () => {
  const { updatePlan, user } = useOutletContext<AppContextType>();
  const navigate = useNavigate();

  const [selectedDuration, setSelectedDuration] = useState<PlanDuration>('monthly');
  const [selectedPlan, setSelectedPlan] = useState<SubscriptionPlan | null>(null);
  const [paymentStep, setPaymentStep] = useState(0); 

  // Payment Form State
  const [selectedWallet, setSelectedWallet] = useState('');
  const [userWalletAddress, setUserWalletAddress] = useState('');
  const [transactionHash, setTransactionHash] = useState('');
  const [copySuccess, setCopySuccess] = useState('');

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopySuccess('تم النسخ!');
    setTimeout(() => setCopySuccess(''), 2000);
  };

  const openPaymentModal = (plan: SubscriptionPlan) => {
    setSelectedPlan(plan);
    setPaymentStep(1);
    // Reset form
    setSelectedWallet('');
    setUserWalletAddress('');
    setTransactionHash('');
  };

  const nextStep = () => {
    if (paymentStep === 2 && !selectedWallet) return alert('يرجى اختيار محفظة');
    if (paymentStep === 3 && !userWalletAddress) return alert('يرجى إدخال عنوان محفظتك');
    if (paymentStep === 4 && !transactionHash) return alert('يرجى إدخال رمز التحقق');

    if (paymentStep === 4) {
        // Finalize transaction
        if (selectedPlan) {
            updatePlan(selectedPlan.id);
        }
    }
    setPaymentStep(prev => prev + 1);
  };

  const handleClose = () => {
      setPaymentStep(0);
      navigate('/profile'); // Redirect to profile to see new badge
  };

  const renderPaymentModal = () => {
    if (!selectedPlan || paymentStep === 0) return null;

    return (
      <div className="fixed inset-0 bg-black/80 z-[60] flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-300">
        <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl">

          {/* Header */}
          <div className="bg-gray-50 p-4 border-b flex justify-between items-center">
            <h3 className="font-bold text-lg">
              {paymentStep === 5 ? 'تمت العملية' : `خطوة ${paymentStep} من 4`}
            </h3>
            <button onClick={() => setPaymentStep(0)} className="p-1 hover:bg-gray-200 rounded-full">
              <X size={20} />
            </button>
          </div>

          {/* Content */}
          <div className="p-6">

            {/* Step 1: Confirmation */}
            {paymentStep === 1 && (
              <div className="space-y-4 text-center">
                <div className="w-16 h-16 bg-black text-white rounded-full flex items-center justify-center mx-auto mb-4">
                  <CreditCard size={32} />
                </div>
                <h4 className="text-xl font-bold">تأكيد الاشتراك</h4>
                <div className="bg-gray-50 p-4 rounded-xl border">
                  <p className="font-bold text-lg">{selectedPlan.title}</p>
                  <p className="text-gray-500 text-sm">مدة الاشتراك: {
                    selectedDuration === 'daily' ? 'يومي' : selectedDuration === 'monthly' ? 'شهري' : 'سنوي'
                  }</p>
                  <p className="text-2xl font-extrabold mt-2">{selectedPlan.prices[selectedDuration]} ﷼</p>
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold hover:scale-[1.02] transition">
                  تأكيد والمتابعة
                </button>
              </div>
            )}

            {/* Step 2: Select Wallet */}
            {paymentStep === 2 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg mb-2">اختر طريقة الدفع</h4>
                <p className="text-xs text-gray-500 mb-4">اختر المحفظة التي ستقوم بالتحويل إليها:</p>
                <div className="max-h-60 overflow-y-auto space-y-2 pr-1">
                  {WALLETS.map(w => (
                    <div 
                      key={w.name}
                      onClick={() => setSelectedWallet(w.name)}
                      className={`p-3 rounded-xl border cursor-pointer flex justify-between items-center transition ${selectedWallet === w.name ? 'border-black bg-black text-white' : 'border-gray-200 hover:bg-gray-50'}`}
                    >
                      <span className="font-bold">{w.name}</span>
                      <span className="text-xs opacity-70">{w.symbol}</span>
                    </div>
                  ))}
                </div>
                {selectedWallet && (
                   <div className="bg-gray-100 p-3 rounded-lg mt-4 text-xs break-all relative">
                     <p className="font-mono text-gray-600 mb-1">عنوان المحفظة:</p>
                     {WALLETS.find(w => w.name === selectedWallet)?.address}
                     <button 
                        onClick={() => handleCopy(WALLETS.find(w => w.name === selectedWallet)?.address || '')}
                        className="absolute top-2 left-2 bg-black text-white p-1 rounded"
                     >
                       <Copy size={12} />
                     </button>
                     {copySuccess && <span className="absolute bottom-1 left-2 text-green-600 font-bold">{copySuccess}</span>}
                   </div>
                )}
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  التالي
                </button>
              </div>
            )}

            {/* Step 3: User Wallet */}
            {paymentStep === 3 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg">عنوان محفظتك</h4>
                <p className="text-sm text-gray-500">يرجى لصق عنوان المحفظة التي قمت بالتحويل منها لنتحقق من المصدر.</p>
                <div className="relative">
                    <Wallet className="absolute top-3 right-3 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      value={userWalletAddress}
                      onChange={(e) => setUserWalletAddress(e.target.value)}
                      placeholder="لصق عنوان محفظتك هنا..."
                      className="w-full p-3 pr-10 bg-gray-50 rounded-xl border focus:border-black outline-none font-mono text-sm"
                    />
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  التالي
                </button>
              </div>
            )}

            {/* Step 4: Transaction Hash */}
            {paymentStep === 4 && (
              <div className="space-y-4">
                <h4 className="font-bold text-lg">إثبات الدفع</h4>
                <p className="text-sm text-gray-500">يرجى لصق رمز التحقق من المعاملة (Hash / Transaction ID).</p>
                <div className="relative">
                    <ShieldCheck className="absolute top-3 right-3 text-gray-400" size={20} />
                    <input 
                      type="text" 
                      value={transactionHash}
                      onChange={(e) => setTransactionHash(e.target.value)}
                      placeholder="Transaction Hash / ID..."
                      className="w-full p-3 pr-10 bg-gray-50 rounded-xl border focus:border-black outline-none font-mono text-sm"
                    />
                </div>
                <button onClick={nextStep} className="w-full bg-black text-white py-3 rounded-xl font-bold mt-4">
                  إتمام الاشتراك
                </button>
              </div>
            )}

            {/* Step 5: Success */}
            {paymentStep === 5 && (
              <div className="text-center py-8 space-y-4 animate-in zoom-in duration-300">
                <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto">
                  <Check size={40} strokeWidth={3} />
                </div>
                <h4 className="text-2xl font-bold">تم الاشتراك بنجاح!</h4>
                <p className="text-gray-500">لقد تم تفعيل الباقة: <span className="font-bold text-black">{selectedPlan.title}</span><br/>استمتع بالمزايا الجديدة.</p>
                <button onClick={handleClose} className="w-full bg-gray-100 text-black py-3 rounded-xl font-bold mt-4 hover:bg-gray-200">
                  إغلاق والعودة
                </button>
              </div>
            )}

          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">

      {/* Header */}
      <div className="text-center space-y-4">
        <h1 className="text-3xl font-extrabold tracking-tight">اختر خطة الاشتراك</h1>
        <p className="text-gray-500 text-sm max-w-md mx-auto">خطتك الحالية: <span className="font-bold text-black">{SUBSCRIPTION_PLANS.find(p => p.id === user.planId)?.title}</span></p>

        {/* Duration Tabs */}
        <div className="flex justify-center p-1 bg-gray-100 rounded-full w-max mx-auto">
          {(['daily', 'monthly', 'yearly'] as PlanDuration[]).map((d) => (
            <button
              key={d}
              onClick={() => setSelectedDuration(d)}
              className={`px-6 py-2 rounded-full text-sm font-bold transition-all duration-300 ${
                selectedDuration === d 
                ? 'bg-black text-white shadow-md' 
                : 'text-gray-500 hover:text-black'
              }`}
            >
              {d === 'daily' ? 'يومي' : d === 'monthly' ? 'شهري' : 'سنوي'}
            </button>
          ))}
        </div>
      </div>

      {/* Pricing Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {SUBSCRIPTION_PLANS.map((plan) => {
          const isCurrent = user.planId === plan.id;
          return (
            <div 
                key={plan.id} 
                className={`relative flex flex-col p-6 rounded-3xl border transition-all duration-300 ${
                isCurrent
                    ? 'bg-green-50 border-green-500 shadow-md order-first'
                    : plan.isPopular 
                    ? 'bg-black text-white border-black shadow-xl scale-[1.02]' 
                    : 'bg-white text-black border-gray-100 hover:border-gray-300 shadow-sm'
                }`}
            >
                {plan.isPopular && !isCurrent && (
                <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-yellow-400 text-black text-[10px] font-extrabold px-3 py-1 rounded-full">
                    الأكثر طلباً
                </span>
                )}
                {isCurrent && (
                <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-green-500 text-white text-[10px] font-extrabold px-3 py-1 rounded-full">
                    باقتك الحالية
                </span>
                )}

                <div className="mb-4">
                <h3 className="text-lg font-bold">{plan.title}</h3>
                <p className={`text-xs ${plan.isPopular && !isCurrent ? 'text-gray-400' : 'text-gray-500'}`}>{plan.description}</p>
                </div>

                <div className="mb-6">
                <span className="text-3xl font-extrabold">{plan.prices[selectedDuration]}</span>
                <span className="text-sm mx-1">﷼</span>
                <span className={`text-xs ${plan.isPopular && !isCurrent ? 'text-gray-500' : 'text-gray-400'}`}>
                    / {selectedDuration === 'daily' ? 'يوم' : selectedDuration === 'monthly' ? 'شهر' : 'سنة'}
                </span>
                </div>

                <ul className="space-y-3 mb-8 flex-1">
                {plan.features.map((feature, i) => (
                    <li key={i} className="flex items-center gap-2 text-sm">
                    <div className={`p-0.5 rounded-full ${plan.isPopular && !isCurrent ? 'bg-white/20' : 'bg-black/5'}`}>
                        <Check size={12} className={plan.isPopular && !isCurrent ? 'text-white' : 'text-black'} />
                    </div>
                    <span className={plan.isPopular && !isCurrent ? 'text-gray-300' : 'text-gray-600'}>{feature}</span>
                    </li>
                ))}
                </ul>

                <button 
                disabled={isCurrent}
                onClick={() => openPaymentModal(plan)}
                className={`w-full py-3 rounded-xl font-bold transition ${
                    isCurrent 
                    ? 'bg-green-600 text-white cursor-default'
                    : plan.isPopular 
                    ? 'bg-white text-black hover:bg-gray-200' 
                    : 'bg-black text-white hover:bg-gray-800'
                }`}
                >
                {isCurrent ? 'مشترك حالياً' : 'اشترك الآن'}
                </button>
            </div>
          );
        })}
      </div>

      {renderPaymentModal()}

    </div>
  );
};

export default Services;

import React, { useState } from 'react';
import { Upload, X, Lock } from 'lucide-react';
import { useOutletContext, Link } from 'react-router-dom';
import { AppContextType } from '../types';
import { SUBSCRIPTION_PLANS } from '../constants';

const AddProject: React.FC = () => {
  const { user, userProjects, addProject } = useOutletContext<AppContextType>();
  const [name, setName] = useState('');

  const currentPlan = SUBSCRIPTION_PLANS.find(p => p.id === user.planId);
  const limit = currentPlan?.projectLimit || 0;
  const currentCount = userProjects.length;
  const isLimitReached = currentCount >= limit;

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (isLimitReached) return;

      const newProject = {
          id: Date.now().toString(),
          name,
          description: 'مشروع جديد',
          developer: user.username,
          downloads: 0,
          views: 0,
          likes: 0,
          type: 'App',
          isPaid: false
      };
      addProject(newProject);
      setName('');
      alert('تم إرسال طلب المشروع بنجاح!');
  };

  if (isLimitReached) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] text-center space-y-6 animate-in fade-in">
             <div className="bg-gray-100 p-6 rounded-full">
                <Lock size={48} className="text-gray-400" />
             </div>
             <div>
                <h2 className="text-2xl font-bold mb-2">عذراً، وصلت للحد الأقصى</h2>
                <p className="text-gray-500 max-w-xs mx-auto">باقتك الحالية ({currentPlan?.title}) تسمح بـ {limit} مشروع فقط. قم بترقية باقتك لإضافة المزيد.</p>
             </div>
             <div className="flex flex-col gap-3 w-full max-w-xs">
                 <Link to="/services" className="w-full bg-black text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2">
                    ترقية الباقة الآن
                 </Link>
                 <Link to="/" className="w-full bg-gray-100 text-black py-3 rounded-xl font-bold">
                    العودة للرئيسية
                 </Link>
             </div>
        </div>
      );
  }

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex justify-between items-center">
            <h1 className="text-2xl font-bold">إضافة مشروع جديد</h1>
            <span className="text-xs bg-gray-100 px-3 py-1 rounded-full font-bold text-gray-500">
                المتبقي: {limit - currentCount}
            </span>
        </div>
        <p className="text-gray-500 text-sm">شارك تطبيقك مع مجتمع ideas</p>

        <form className="space-y-4" onSubmit={handleSubmit}>
            <div>
                <label className="block text-sm font-bold mb-2">اسم التطبيق</label>
                <input 
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                    className="w-full p-3 bg-gray-50 rounded-xl border focus:border-black outline-none" 
                    placeholder="مثال: متجر الرياض" 
                />
            </div>

             <div>
                <label className="block text-sm font-bold mb-2">الوصف</label>
                <textarea className="w-full p-3 bg-gray-50 rounded-xl border focus:border-black outline-none h-24" placeholder="اشرح فكرة تطبيقك..." />
            </div>

