                    </div>
                    <p className="text-gray-500 text-xs mt-1 line-clamp-2">{app.description}</p>
                    <p className="text-gray-400 text-[10px] mt-2">Developed by: {app.developer}</p>
                  </div>
                </div>

                <div className="mt-4 pt-4 border-t border-gray-50 flex justify-between items-center text-gray-500 text-xs">
                  <div className="flex items-center gap-4">
                      <span className="flex items-center gap-1"><Download size={14} /> {app.downloads.toLocaleString()}</span>
                      <span className="flex items-center gap-1"><Eye size={14} /> {app.views.toLocaleString()}</span>
                      <span className="flex items-center gap-1"><Heart size={14} /> {app.likes.toLocaleString()}</span>
                  </div>
                  <button className="p-2 hover:bg-gray-100 rounded-full"><Share2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-12 text-gray-400">
             <Inbox size={48} className="mb-2 opacity-20" />
             <p className="text-sm">لا توجد مشاريع حالياً</p>
          </div>
        )}
      </section>
    </div>
  );
};

