import React, { useState, useEffect, useRef } from 'react';
import { Send, Mic, MapPin, Image as ImageIcon, Mail } from 'lucide-react';
import { ChatMessage, AppContextType } from '../types';
import { useOutletContext } from 'react-router-dom';

const Chat: React.FC = () => {
  const { user } = useOutletContext<AppContextType>();
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;

    const newMessage: ChatMessage = {
      id: Date.now().toString(),
      senderId: 'user',
      text: inputText,
      timestamp: Date.now(),
      type: 'text'
    };

    setMessages(prev => [...prev, newMessage]);
    setInputText('');

    // Simulate Developer Reply (Simplified)
    setTimeout(() => {
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        senderId: 'dev',
        text: 'شكراً لتواصلك. أنا مشغول حالياً، يرجى إرسال استفسارك عبر البريد الإلكتروني لضمان الرد السريع.',
        timestamp: Date.now(),
        type: 'text'
      }]);
    }, 1500);
  };

  const handleSendToGmail = () => {
      const subject = encodeURIComponent("استفسار من الدردشة - ideas");
      // Aggregate chat history
      const history = messages.map(m => `[${m.senderId === 'user' ? user.fullName : 'Jacob'}]: ${m.text}`).join('\n');

      const body = encodeURIComponent(`
مرحباً Jacob،

أرسل لك هذا الاستفسار من المحادثة:

${history}

----------------
${inputText ? `رسالة إضافية: ${inputText}` : ''}
