import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './components/Layout';
import Home from './pages/Home';
import Profile from './pages/Profile';
import Services from './pages/Services';
import Chat from './pages/Chat';
import SupportAI from './pages/SupportAI';
import AddProject from './pages/AddProject';
import UsagePolicy from './pages/UsagePolicy';
import PrivacyPolicy from './pages/PrivacyPolicy';
import Register from './pages/Register';
import { User, UserRole, AppProject, AppContextType } from './types';

const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Application State
  const [user, setUser] = useState<User>({
      id: '1',
      username: '@guest',
      fullName: 'زائر',
      email: '',
      avatar: 'https://ui-avatars.com/api/?name=Guest&background=f3f4f6&color=000',
      role: UserRole.USER,
      points: 0,
      planId: 'starter', // Default Plan
      joinDate: new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' })
  });

  const [userProjects, setUserProjects] = useState<AppProject[]>([]);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
    if (!isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  };

  const handleRegister = (name: string, email: string) => {
    setUser(prev => ({
        ...prev,
        fullName: name,
        email: email,
        username: `@${email.split('@')[0]}`,
        avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=000&color=fff`,
        points: 50 // Welcome bonus
    }));
    setIsAuthenticated(true);
  };

  const updatePlan = (planId: string) => {
      setUser(prev => ({ ...prev, planId }));
  };

  const addProject = (project: AppProject) => {
      setUserProjects(prev => [...prev, project]);
  };

  const updateUser = (data: Partial<User>) => {
      setUser(prev => ({ ...prev, ...data }));
  };

  const logout = () => {
      setIsAuthenticated(false);
      setUserProjects([]);
      setUser({
          id: '1',
          username: '@guest',
          fullName: 'زائر',
          email: '',
          avatar: 'https://ui-avatars.com/api/?name=Guest&background=f3f4f6&color=000',
          role: UserRole.USER,
          points: 0,
          planId: 'starter',
          joinDate: new Date().toLocaleDateString('en-US', { month: 'short', year: 'numeric' })
      });
  };

  // Context Value to pass down
  const appContextValue: AppContextType = {
      user,
      userProjects,
      updatePlan,
      addProject,
      updateUser,
      logout,
      isDarkMode,
      toggleTheme
  };

  return (
    <HashRouter>
      <Routes>
        {/* Public Routes */}
        <Route path="/register" element={
            !isAuthenticated ? <Register onRegister={handleRegister} /> : <Navigate to="/" />
        } />
        <Route path="/usage-policy" element={<UsagePolicy />} />
        <Route path="/privacy-policy" element={<PrivacyPolicy />} />

        {/* Protected Routes */}
        <Route path="/" element={isAuthenticated ? <Layout toggleTheme={toggleTheme} isDarkMode={isDarkMode} contextValue={appContextValue} /> : <Navigate to="/register" />}>
          <Route index element={<Home />} />
          <Route path="profile" element={<Profile />} />
          <Route path="services" element={<Services />} />
          <Route path="chat" element={<Chat />} />
          <Route path="support" element={<SupportAI />} />
          <Route path="add-project" element={<AddProject />} />
        </Route>
      </Routes>
    </HashRouter>
  );
};

export default App;

