                    {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </span>
              )}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-3 border-t bg-white">
        <div className="flex items-center gap-2 bg-gray-50 p-2 rounded-full border border-gray-100 focus-within:border-black transition-colors">
            <button className="p-2 text-gray-400 hover:text-black transition"><Mic size={20} /></button>
            <button className="p-2 text-gray-400 hover:text-black transition"><ImageIcon size={20} /></button>
            <input 
                type="text" 
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendEmail()}
                placeholder="اكتب رسالتك للمطور هنا..." 
                className="flex-1 bg-transparent focus:outline-none px-2 text-sm"
            />
            <button 
                onClick={handleSendEmail} 
                className="p-2 bg-black text-white rounded-full hover:scale-105 transition flex items-center gap-2 px-4"
            >
                <span className="text-xs font-bold hidden sm:inline">إرسال بريد</span>
                <Send size={16} className={inputText ? "animate-pulse" : ""} />
            </button>
        </div>
        <p className="text-[10px] text-gray-400 text-center mt-2">
            سيتم فتح تطبيق البريد الإلكتروني لإتمام الإرسال
        </p>
      </div>

    </div>
  );
};

