import React, { useState, useEffect } from 'react';
import { Download, Eye, Heart, Share2, Filter, Inbox, Check } from 'lucide-react';
import { useOutletContext } from 'react-router-dom';
import { AppContextType, AppProject } from '../types';

const Home: React.FC = () => {
  const { user, userProjects } = useOutletContext<AppContextType>();
  const [filter, setFilter] = useState('All');

  // Local state to manage interactions (Likes, Downloads) for display purposes
  const [displayApps, setDisplayApps] = useState<AppProject[]>([]);

  useEffect(() => {
    // Only display user projects, removed MOCK_APPS content
    setDisplayApps(userProjects);
  }, [userProjects]);

  const handleLike = (id: string) => {
    setDisplayApps(prev => prev.map(app => {
        if (app.id === id) {
            // Toggle logic simulation
            return { ...app, likes: app.likes + 1 }; 
        }
        return app;
    }));
  };

  const handleDownload = (id: string) => {
    setDisplayApps(prev => prev.map(app => {
        if (app.id === id) {
            return { ...app, downloads: app.downloads + 1 };
        }
        return app;
    }));
    alert('بدأ التحميل... (محاكاة)');
  };

  const handleShare = async (app: AppProject) => {
      if (navigator.share) {
          try {
              await navigator.share({
                  title: app.name,
                  text: `حمل تطبيق ${app.name} الآن من منصة ideas!`,
                  url: window.location.href
              });
          } catch (err) {
              console.log('Share failed', err);
          }
      } else {
          navigator.clipboard.writeText(`${app.name} - ideas App`);
          alert('تم نسخ اسم التطبيق!');
      }
  };

  const filteredApps = filter === 'All' ? displayApps : displayApps.filter(app => app.type === filter);

  return (
    <div className="space-y-6 animate-in fade-in duration-500 min-h-[80vh]">

      {/* Filter Header */}
      <div className="sticky top-0 bg-white/95 backdrop-blur-sm z-10 pb-2 pt-2">
          <div className="flex items-center justify-between mb-3">
              <h2 className="text-xl font-bold">المعرض</h2>
              <button className="p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition"><Filter size={18} /></button>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['All', 'Game', 'App', 'Store', 'Site'].map((type) => (
              <button
                key={type}
                onClick={() => setFilter(type)}
                className={`px-5 py-2 rounded-full text-xs font-bold whitespace-nowrap transition shadow-sm ${
                  filter === type ? 'bg-black text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                {type === 'All' ? 'الكل' : type}
              </button>
            ))}
          </div>
      </div>

      {/* Apps Grid */}
      {filteredApps.length > 0 ? (
        <div className="grid gap-4">
          {filteredApps.map((app) => (
            <div key={app.id} className="border border-gray-100 p-4 rounded-3xl shadow-sm hover:shadow-md transition-all bg-white group">
              <div className="flex gap-4">
                <div className="relative">
                     <img src={app.icon || `https://ui-avatars.com/api/?name=${app.name}`} alt={app.name} className="w-20 h-20 rounded-2xl object-cover bg-gray-200 shadow-inner" />
                     {app.isPaid && <span className="absolute -top-2 -right-2 bg-yellow-400 text-black text-[10px] font-bold px-2 py-0.5 rounded-full shadow-sm">Pro</span>}
                </div>

                <div className="flex-1">
                  <div className="flex justify-between items-start">
                    <h3 className="font-bold text-lg leading-tight">{app.name}</h3>
                    <div className="flex gap-1">
                         <span className="text-[10px] bg-gray-100 px-2 py-1 rounded-full text-gray-600">{app.type}</span>
                    </div>
                  </div>
                  <p className="text-gray-500 text-xs mt-1 line-clamp-2 leading-relaxed">{app.description}</p>
                  <p className="text-gray-400 text-[10px] mt-2 flex items-center gap-1">
                    <Check size={10} className="text-blue-500" /> {app.developer}
                  </p>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t border-gray-50 flex justify-between items-center">
                <div className="flex items-center gap-5 text-gray-400">
                    <button 
                        onClick={() => handleDownload(app.id)}
                        className="flex items-center gap-1 text-xs hover:text-black transition group-hover/btn:text-black"
                        title="تحميل"
                    >
                        <Download size={16} /> 
                        <span className="font-medium">{app.downloads.toLocaleString()}</span>
                    </button>
                    <div className="flex items-center gap-1 text-xs">
                        <Eye size={16} /> 
                        <span>{app.views.toLocaleString()}</span>
                    </div>
                    <button 
                        onClick={() => handleLike(app.id)}
                        className="flex items-center gap-1 text-xs hover:text-red-500 transition"
                        title="إعجاب"
                    >
                        <Heart size={16} className={app.likes > 1000 ? "fill-red-500 text-red-500" : ""} /> 
                        <span>{app.likes.toLocaleString()}</span>
                    </button>
                </div>
                <button 
                    onClick={() => handleShare(app)}
                    className="p-2 bg-gray-50 text-gray-600 rounded-full hover:bg-black hover:text-white transition"
                    title="مشاركة"
                >
                    <Share2 size={16} />
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-20 text-gray-400">
           <div className="bg-gray-100 p-6 rounded-full mb-4">
               <Inbox size={48} className="opacity-30" />
           </div>
           <p className="font-bold">لا توجد مشاريع حالياً</p>
           <p className="text-xs mt-1">كن أول من يضيف مشروعاً!</p>
        </div>
      )}
    </div>
  );
};

