                                    <div key={n.id} className={`p-3 border-b dark:border-gray-700 text-xs hover:bg-gray-50 dark:hover:bg-gray-700 ${!n.read ? 'bg-blue-50/50 dark:bg-blue-900/10' : ''}`}>
