import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateSupportResponse = async (userQuery: string): Promise<string> => {
  if (!apiKey) {
    return "عذراً، خدمة الذكاء الاصطناعي غير متوفرة حالياً. يرجى التواصل عبر البريد الإلكتروني: jikob67@gmail.com";
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userQuery,
      config: {
        systemInstruction: `You are a helpful AI support assistant for an app development platform called 'Ideas', managed by developer Jacob Al Cadi. 
        Your goal is to help users with their questions about app development services, pricing, and technical issues.

        Key Info:
        - Developer: Jacob Al Cadi
        - Email: jikob67@gmail.com
        - Support sites: https://jacobalcadiapps.wordpress.com, https://jacobalcadiapps.blogspot.com
        - Payment: Crypto only (Solana, BTC, ETH, etc.)

        Answer in Arabic. Be polite, professional, and concise. If you cannot solve a technical issue, refer them to the email.`,
      }
    });
    return response.text || "لم أتمكن من فهم طلبك. يرجى المحاولة مرة أخرى.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "حدث خطأ أثناء الاتصال بالمساعد الذكي. يرجى المحاولة لاحقاً.";
  }
};
